class PhotoUploadScreen extends StatefulWidget {
  @override
  _PhotoUploadScreenState createState() => _PhotoUploadScreenState();
}

class _PhotoUploadScreenState extends State<PhotoUploadScreen> {
  final ImagePicker _picker = ImagePicker();
  File? _selectedImage;
  bool _isUploading = false;
  String _uploadStatus = '';
  Map<String, dynamic>? _analysisResults;

  final String awsAccessKey = dotenv.env['AWS_ACCESS_KEY'] ?? '';
  final String awsSecretKey = dotenv.env['AWS_SECRET_KEY'] ?? '';
  final String awsRegion = dotenv.env['AWS_REGION'] ?? 'us-east-1';
  final String s3Bucket = dotenv.env['S3_BUCKET'] ?? '';
  final String googleApiKey = dotenv.env['GOOGLE_CLOUD_API_KEY'] ?? '';

  Future<void> _pickImage() async {
    final XFile? image = await _picker.pickImage(source: ImageSource.gallery);
    if (image != null) {
      setState(() {
        _selectedImage = File(image.path);
        _uploadStatus = '';
        _analysisResults = null;
      });
    }
  }

  Future<void> _uploadAndAnalyze() async {
    if (_selectedImage == null) return;

    setState(() {
      _isUploading = true;
      _uploadStatus = 'Uploading to S3...';
    });

    try {
      String fileName = 'photo_${DateTime.now().millisecondsSinceEpoch}.jpg';
      bool uploadSuccess = await _uploadToS3(_selectedImage!, fileName);

      if (uploadSuccess) {
        setState(() {
          _uploadStatus = 'Upload successful! Analyzing image...';
        });

        await _analyzeWithVision(_selectedImage!);

        setState(() {
          _uploadStatus = 'Analysis complete!';
        });
      }
    } catch (e) {
      setState(() {
        _uploadStatus = 'Error: $e';
      });
    } finally {
      setState(() {
        _isUploading = false;
      });
    }
  }

  Future<bool> _uploadToS3(File file, String fileName) async {
    final bytes = await file.readAsBytes();
    final contentType = 'image/jpeg';
    final dateTime = DateTime.now().toUtc();
    final dateStamp = DateFormat('yyyyMMdd').format(dateTime);
    final amzDate = DateFormat("yyyyMMdd'T'HHmmss'Z'").format(dateTime);

    final url = 'https://$s3Bucket.s3.$awsRegion.amazonaws.com/$fileName';

    final canonicalRequest = _createCanonicalRequest(
      'PUT',
      '/$fileName',
      '',
      {
        'host': '$s3Bucket.s3.$awsRegion.amazonaws.com',
        'x-amz-date': amzDate,
        'x-amz-content-sha256': sha256.convert(bytes).toString(),
      },
      sha256.convert(bytes).toString(),
    );

    final stringToSign = _createStringToSign(
      amzDate,
      dateStamp,
      awsRegion,
      canonicalRequest,
    );

    final signature = _calculateSignature(
      awsSecretKey,
      dateStamp,
      awsRegion,
      stringToSign,
    );

    final authorization = _createAuthorizationHeader(
      awsAccessKey,
      dateStamp,
      awsRegion,
      signature,
    );

    final response = await http.put(
      Uri.parse(url),
      headers: {
        'Host': '$s3Bucket.s3.$awsRegion.amazonaws.com',
        'x-amz-date': amzDate,
        'x-amz-content-sha256': sha256.convert(bytes).toString(),
        'Authorization': authorization,
        'Content-Type': contentType,
      },
      body: bytes,
    );

    return response.statusCode == 200;
  }

  String _createCanonicalRequest(String method, String uri, String queryString,
      Map<String, String> headers, String payloadHash) {
    final sortedHeaders = headers.keys.toList()..sort();
    final canonicalHeaders =
        sortedHeaders.map((key) => '${key.toLowerCase()}:${headers[key]}\n').join();
    final signedHeaders = sortedHeaders.map((key) => key.toLowerCase()).join(';');

    return '$method\n$uri\n$queryString\n$canonicalHeaders\n$signedHeaders\n$payloadHash';
  }

  String _createStringToSign(
      String amzDate, String dateStamp, String region, String canonicalRequest) {
    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    final hashedCanonicalRequest = sha256.convert(utf8.encode(canonicalRequest)).toString();
    return 'AWS4-HMAC-SHA256\n$amzDate\n$credentialScope\n$hashedCanonicalRequest';
  }

  String _calculateSignature(
      String secretKey, String dateStamp, String region, String stringToSign) {
    final kDate = _hmacSha256(utf8.encode('AWS4$secretKey'), utf8.encode(dateStamp));
    final kRegion = _hmacSha256(kDate, utf8.encode(region));
    final kService = _hmacSha256(kRegion, utf8.encode('s3'));
    final kSigning = _hmacSha256(kService, utf8.encode('aws4_request'));
    final signature = _hmacSha256(kSigning, utf8.encode(stringToSign));
    return signature.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
  }

  List<int> _hmacSha256(List<int> key, List<int> data) {
    final hmac = Hmac(sha256, key);
    return hmac.convert(data).bytes;
  }

  String _createAuthorizationHeader(
      String accessKey, String dateStamp, String region, String signature) {
    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    return 'AWS4-HMAC-SHA256 Credential=$accessKey/$credentialScope, SignedHeaders=host;x-amz-content-sha256;x-amz-date, Signature=$signature';
  }

  Future<void> _analyzeWithVision(File file) async {
    final bytes = await file.readAsBytes();
    final base64Image = base64Encode(bytes);

    final url =
        'https://vision.googleapis.com/v1/images:annotate?key=$googleApiKey';

    final response = await http.post(
      Uri.parse(url),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({
        'requests': [
          {
            'image': {'content': base64Image},
            'features': [
              {'type': 'LABEL_DETECTION', 'maxResults': 10},
              {'type': 'TEXT_DETECTION'},
              {'type': 'FACE_DETECTION'},
            ]
          }
        ]
      }),
    );

    if (response.statusCode == 200) {
      setState(() {
        _analysisResults = jsonDecode(response.body);
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Photo Analyzer')),
      body: SingleChildScrollView(
        padding: EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            if (_selectedImage != null)
              Image.file(_selectedImage!, height: 300, fit: BoxFit.cover),
            SizedBox(height: 20),
            ElevatedButton.icon(
              onPressed: _isUploading ? null : _pickImage,
              icon: Icon(Icons.photo_library),
              label: Text('Select Photo'),
            ),
            SizedBox(height: 10),
            ElevatedButton.icon(
              onPressed: _selectedImage == null || _isUploading
                  ? null
                  : _uploadAndAnalyze,
              icon: Icon(Icons.cloud_upload),
              label: Text('Upload & Analyze'),
            ),
            SizedBox(height: 20),
            if (_uploadStatus.isNotEmpty)
              Text(_uploadStatus,
                  style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
            SizedBox(height: 20),
            if (_analysisResults != null) _buildAnalysisResults(),
          ],
        ),
      ),
    );
  }

  Widget _buildAnalysisResults() {
    final responses = _analysisResults!['responses'] as List;
    if (responses.isEmpty) return SizedBox();

    final response = responses[0];
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text('Analysis Results:',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
        SizedBox(height: 10),
        if (response['labelAnnotations'] != null) ...[
          Text('Labels:', style: TextStyle(fontWeight: FontWeight.bold)),
          ...(response['labelAnnotations'] as List).map((label) => Text(
              '- ${label['description']} (${(label['score'] * 100).toStringAsFixed(1)}%)')),
        ],
        SizedBox(height: 10),
        if (response['faceAnnotations'] != null) ...[
          Text('Faces Detected: ${response['faceAnnotations'].length}',
              style: TextStyle(fontWeight: FontWeight.bold)),
        ],
      ],
    );
  }
